import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import EditProfile from "../users/EditProfile";

export default function UsrProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [showEditProfile, setShowEditProfile] = useState(false);

  useEffect(() => {
    const raw = localStorage.getItem("user");
    const stored = raw ? JSON.parse(raw) : null;

    if (!stored?.email) return;

    axios
      .get(`http://localhost:8086/user/profile?email=${stored.email}`)
      .then((res) => setUser(res.data))
      .catch(console.log);
  }, []);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200">
        <div className="backdrop-blur-lg bg-white/30 p-6 rounded-xl shadow-lg">
          Loading profile...
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-200 via-purple-200 to-pink-200 p-6">

      {/* ✅ MODAL */}
      {showEditProfile && (
        <EditProfile
          user={user}
          closeModal={() => setShowEditProfile(false)}
          onUpdated={(updatedUser) => setUser(updatedUser)}
        />
      )}

      <div className="backdrop-blur-xl bg-white/30 border border-white/40 shadow-2xl rounded-2xl p-8 w-full max-w-md">

        {/* PROFILE */}
        <div className="text-center">
          <img
            src={
              user.profileImage ||
              `https://ui-avatars.com/api/?name=${user.username}`
            }
            className="w-28 h-28 rounded-full mx-auto border-4 border-white shadow-lg"
            alt="profile"
          />

          <h2 className="text-2xl font-bold mt-4">{user.name}</h2>
          <p className="text-gray-600">{user.email}</p>

          <span className="mt-2 inline-block px-3 py-1 text-xs bg-indigo-500 text-white rounded-full">
            {user.role}
          </span>
        </div>

        {/* INFO */}
        <div className="mt-6 space-y-3 text-sm">
          <div className="flex justify-between bg-white/20 p-2 rounded-lg">
            <span>Username</span>
            <span>{user.username}</span>
          </div>
        </div>

        {/* BUTTONS */}
        <div className="mt-6 space-y-3">

          <button
            onClick={() => setShowEditProfile(true)}
            className="w-full bg-gradient-to-r from-indigo-500 to-purple-600 text-white py-2 rounded-lg hover:scale-105 transition"
          >
            Edit Profile
          </button>

          <button
            onClick={() => {
              localStorage.clear();
              navigate("/");
            }}
            className="w-full bg-red-500 text-white py-2 rounded-lg hover:bg-red-600 transition"
          >
            Logout
          </button>

        </div>
      </div>
    </div>
  );
}
